void SetTextMode()

{

   if(textMode==0)

   {

      playStatus = 0;

      Sound_Holder.Stop(0);

      Text_Holder.HideText(0);

      Text_Holder.StopSynchroText(0);

      Sound_Holder.SetPlayDSoundParameters(1,0,0,0);

   }

   else

   {

      Transparent_Video_Holder.Stop();



      playStatus = 1;   

      Sound_Holder.SetPlayDSoundParameters(1,-1000,0,0);

      Sound_Holder.PlayDSound(0);

      Text_Holder.SetTextOffsets(0,0,0);

      Text_Holder.DisableMouse(0);

      Text_Holder.ShowText(0);

   }

}











void Transparent_Video_Holder.TheEnd(int videoID)

{

   if( textMode )

      Transparent_Video_Holder.ShowFirsLastVideoFrame(curVdo+1);

   else

      Sound_Holder.SetPlayDSoundParameters(1,0,0,0);



   curVdo++;

   if(curVdo>4)

   {   

      Sprite_Holder.ChangePhase(0,0);

      Sprite_Holder.ChangePhase(1,0);

      Sprite_Holder.ChangePhase(2,0);

      Sprite_Holder.ChangePhase(3,0);

      Sprite_Holder.ChangePhase(4,0);



      Sprite_Holder.ShowSprite(0);

      Sprite_Holder.ShowSprite(1);

      Sprite_Holder.ShowSprite(2);

      Sprite_Holder.ShowSprite(3);

      Sprite_Holder.ShowSprite(4);

      Transparent_Video_Holder.HideFirsLastVideoFrame(curVdo-1);

      curVdo=0;

      inw[0]=0;

      inw[1]=0;

      inw[2]=0;

      inw[3]=0;

      inw[4]=0;

      zwCnt=0;

   }

   curPlay=0;

}





void Sprite_Holder.MouseMoveIn(int spriteID)

{

   if( textMode ) return;



   if(inw[spriteID]==0)   SetCursor(1);

}





void Sprite_Holder.MouseMoveOut(int spriteID)

{

   if( textMode ) return;



   if(curVdo==0)   

   {

      SetCursor(0);

   }

}





void Sprite_Holder.MouseClickOnDown(int spriteID)

{

   if( textMode ) return;



   if(inw[spriteID]==0)

   {

      Sound_Holder.PlayDSound(spriteID+2);

      Sprite_Holder.ChangePhase(spriteID,1);

      inw[spriteID]=1;

      zwCnt++;

      SetCursor(0);

   }

   if(zwCnt>4)

   {

      curPlay=1;

      Sound_Holder.SetPlayDSoundParameters(1,-1000,0,0);

      Transparent_Video_Holder.Play(curVdo,0);

      Sprite_Holder.HideSprite(0);

      Sprite_Holder.HideSprite(1);

      Sprite_Holder.HideSprite(2);

      Sprite_Holder.HideSprite(3);

      Sprite_Holder.HideSprite(4);

   }

}





void Transparent_Video_Holder.MouseClickOnDown(int videoID)

{

   if( textMode ) return;



   if(curPlay)   return;

   Transparent_Video_Holder.Play(curVdo,0);

   Transparent_Video_Holder.HideFirsLastVideoFrame(curVdo-1);

}





void Transparent_Video_Holder.MouseMoveIn(int videoID)

{

   if( textMode ) return;



   if(curPlay || curVdo==0)   return;

   SetCursor(1);

}





void Transparent_Video_Holder.MouseMoveOut(int videoID)

{

   if( textMode ) return;

   SetCursor(0);

}





